VALUES
  ('judicial-de09bf8b-moex-00019', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲以彩色影印方式印製美金紙鈔，非常擬真且混入真正美鈔，於存入銀行時被查獲，依實務見解， 甲之行為構成下列何種犯罪？', '["刑法第195條偽造貨幣罪", "刑法第202條偽造郵票罪", "刑法第196條行使偽造貨幣罪", "刑法第201條偽造有價證券罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00020', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '某甲為求脫產，遂與某乙締結土地買賣契約，以假的資金流向，辦理土地登記，順利將甲名下的 土地過戶到乙名下，達到隱匿財產目的，甲與乙的刑責應如何論處？', '["甲與乙合意締結內容不實在土地買賣契約，應構成刑法第210條偽造私文書罪", "甲與乙製作假的資金流向來辦理土地登記，應構成刑法第211條偽造公文書罪", "甲與乙以不實買賣契約辦理土地登記，應構成刑法第214條使公務員登載不實罪", "甲與乙持不實買賣契約辦理土地登記，應構成刑法第216條行使偽造私文書罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00021', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '下列何者不屬於刑法第222條加重強制性交罪？', '["二人以上共同犯強制性交罪", "侵入住宅犯強制性交罪", "以藥劑犯強制性交罪", "冒用公務員名義犯強制性交罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00022', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '關於賭博罪之敘述，下列何者正確？', '["以網際網路之方法賭博財物者，不構成刑法第266條賭博罪", "在公共場所以供人暫時娛樂之物為賭者，構成刑法第266條賭博罪", "在公眾得出入之場所賭博財物時，當場賭博之器具，須屬於犯罪行為人者，始得沒收", "以電子通訊方式賭博財物者，構成刑法第266條賭博罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00023', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲駕駛汽車在路上因超速不慎撞上前方懷胎 30 週之孕婦乙所駕駛之汽車，乙雖奇蹟式毫髮無傷 但是因受撞擊刺激故其胎兒丙提早開始分娩，分娩結束後經醫師檢查始發現丙實際上已因撞擊在 分娩前死於乙子宮內，成為死產。依刑法規定及通說見解，甲對丙應成立何種犯罪？', '["無罪", "刑法第276條之過失致死罪", "刑法第271條第1項之殺人罪", "刑法第291條第1項之墮胎罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00024', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲受邀前往女友乙住處，未料在乙住處發生爭吵，乙命甲離開其住處，甲仍不願離開，有關刑法 第306條之犯罪，下列敘述何者正確？', '["甲之行為符合無故侵入住宅之要件", "甲之行為符合無故隱匿於住宅內之要件", "甲之行為符合受退去要求仍留滯之要件", "甲之行為不成立犯罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00025', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲與乙係同事，素有糾紛，甲見乙高升職位，更加不滿，其明知為不實事項，卻以匿名方式發出 數十封信函給公司同仁，其於匿名信函內稱：乙因與公司高層有婚外情，始得以高升等語。甲應 如何論罪？', '["刑法第309條第1項公然侮辱罪", "刑法第310條第1項誹謗罪", "刑法第310條第2項加重誹謗罪", "不構成犯罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00026', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '依實務見解，下列何種行為會構成刑法第315條之1之窺視竊聽竊錄罪？', '["在捷運車廂內拿密錄器偷拍乘客大腿外側、膝蓋及小腿部位", "在咖啡廳裡用肉耳偷聽隔壁桌客人的對談", "在某人車上裝設GPS追蹤器，長時間蒐集駕駛使用車輛之移動軌跡", "拿望遠鏡在遠處偷看在公園裡開心玩耍的小女孩"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00027', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲因不認同乙所訴求集會遊行議題，持一桶紅色油漆於乙遊行地點立法院前，朝乙頭部由上往下 潑灑，使乙之衣服沾染紅漆而不堪用。甲之刑事責任何者正確？', '["甲成立刑法第309條第2項強暴侮辱罪及第354條毀損罪二罪，從一重處斷", "甲只成立刑法第354條毀損罪一罪", "甲只成立刑法第304條強制罪一罪", "甲只成立刑法第309條第2項強暴侮辱罪一罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00028', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-2909f946', 'sub-judicial-de09bf8b-02', NULL, 'essay', '甲與乙為丙之繼承人，設籍於桃園市的丙死亡時，留有桃園市郵局帳戶
